import { useCallback, useEffect, useSyncExternalStore } from "react";
import { type ThemeId, BUILT_IN_THEMES, THEME_IDS } from "@t3tools/shared/theme";

export type Theme = "system" | ThemeId;
type ThemeSnapshot = {
  theme: Theme;
  systemDark: boolean;
};

const STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;
function emitChange() {
  for (const listener of listeners) listener();
}

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

function getStored(): Theme {
  const raw = localStorage.getItem(STORAGE_KEY);
  // Legacy migration from old "light" / "dark" values
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  if (raw === "system") return "system";
  if (raw !== null && (THEME_IDS as ReadonlyArray<string>).includes(raw)) return raw as ThemeId;
  return "system";
}

function resolveThemeId(theme: Theme, systemDark: boolean): ThemeId {
  if (theme === "system") {
    return systemDark ? "t3-dark" : "t3-light";
  }
  return theme;
}

function applyTheme(theme: Theme, suppressTransitions = false) {
  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }
  const systemDark = getSystemDark();
  const resolvedId = resolveThemeId(theme, systemDark);
  const themeDef = BUILT_IN_THEMES.find((t) => t.id === resolvedId);
  const isDark = themeDef?.isDark ?? (theme === "system" && systemDark);
  document.documentElement.classList.toggle("dark", isDark);
  document.documentElement.setAttribute("data-theme", resolvedId);
  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStored());

function getSnapshot(): ThemeSnapshot {
  const theme = getStored();
  const systemDark = theme === "system" ? getSystemDark() : false;

  if (lastSnapshot && lastSnapshot.theme === theme && lastSnapshot.systemDark === systemDark) {
    return lastSnapshot;
  }

  lastSnapshot = { theme, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    if (getStored() === "system") applyTheme("system", true);
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStored(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const theme = snapshot.theme;

  const resolvedTheme: "light" | "dark" =
    theme === "system"
      ? snapshot.systemDark
        ? "dark"
        : "light"
      : (BUILT_IN_THEMES.find((t) => t.id === theme)?.isDark ? "dark" : "light");

  const setTheme = useCallback((next: Theme) => {
    localStorage.setItem(STORAGE_KEY, next);
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(theme);
  }, [theme]);

  return { theme, setTheme, resolvedTheme } as const;
}

