import { type ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * Mount at the app root to keep the `data-theme` attribute and `.dark` class
 * on `<html>` in sync with localStorage and OS preference changes.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Subscribes to the theme store — side-effects (DOM sync) live in useTheme.
  useTheme();
  return <>{children}</>;
}

