import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { type Theme, useTheme } from "../hooks/useTheme";

const SWATCH_KEYS = ["background", "accent", "sidebar", "editor"] as const;

function ThemeOption({
  label,
  description,
  value,
  selected,
  swatchColors,
  onSelect,
}: {
  label: string;
  description?: string;
  value: Theme;
  selected: boolean;
  swatchColors?: string[];
  onSelect: (v: Theme) => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
          ? "border-primary/60 bg-primary/8 text-foreground"
          : "border-border bg-background text-muted-foreground hover:bg-accent"
      }`}
      onClick={() => onSelect(value)}
    >
      <span className="flex items-center gap-3">
        {swatchColors && swatchColors.length > 0 && (
          <span className="flex gap-1" aria-hidden="true">
            {swatchColors.map((color, i) => (
              <span
                key={i}
                className="size-4 rounded-sm border border-black/10"
                style={{ backgroundColor: color }}
              />
            ))}
          </span>
        )}
        <span className="flex flex-col">
          <span className="text-sm font-medium">{label}</span>
          {description && <span className="text-xs">{description}</span>}
        </span>
      </span>
      {selected && (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          Selected
        </span>
      )}
    </button>
  );
}

export function ThemeSelector() {
  const { theme, setTheme, resolvedTheme } = useTheme();

  return (
