import { BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { type Theme, useTheme } from "../hooks/useTheme";

const SWATCH_KEYS = ["background", "accent", "sidebar", "editor"] as const;

function ThemeOption({
  label,
  description,
  value,
  selected,
  swatchColors,
  onSelect,
}: {
  label: string;
  description?: string;
  value: Theme;
  selected: boolean;
  swatchColors?: string[];
  onSelect: (v: Theme) => void;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={selected}
      className={`flex w-full items-center justify-between rounded-lg border px-3 py-2 text-left transition-colors ${
        selected
